insert into public.lore_entries (slug, title, category, content, pathway, epoch, city, npcs, sequences, tags, token_count)
values
  ('southern-continent-overview', 'The Southern Continent — Overview', 'location', 'The Southern Continent lies across the Berserk Sea from the Northern Continent, the far side of the Five Seas — Berserk to the north, the Sonia Sea east, the Fog Sea west, the Polar Sea south. It is a hot land of jungle and desert, far less developed than the gaslit North, and its native peoples are scattered tribes whose oldest faith was the worship of a death-god. Once it was a single dominion: through the Fourth Epoch the whole continent was the Balam Empire of the Underworld Emperor, until the orthodox gods slew him and the empire fell to ruin. Into that wreckage came the powers of the North. By the present day the Loen Kingdom and the Intis Republic — with Feysac and Feynapotter pressing in — have colonized the old imperial lands, breaking them into East Balam, West Balam, the Star Highlands, and a patchwork of conquered tribes and client states. It is a place of abundant sun, raw wealth, and brutal exploitation, where the colonists grow rich and the subjugated natives nurse a long, smoldering resentment.', null, 5, 'balam', '{}', '{}', ARRAY['southern-continent', 'balam', 'geography', 'colony', 'fifth-epoch'], 235),
  ('balam-colonies', 'East Balam & West Balam — The Colonies', 'location', 'After the Balam Empire fell, its crown passed to the North — to Loen''s Augustus royal house — and its lands were carved into two great colonies. East Balam is the Loen Kingdom''s prize, a contested ground the Feysac Empire has fought it over for years; beneath its plantations and garrisons a secret army still worships the dead god and dreams of resurrecting the empire and driving the foreigners into the sea. West Balam is the Intis Republic''s holding, a wilder country mostly of rainforest, more lawless than the East, where the old traditions of slavery and blood-sacrifice were never fully stamped out — its ports Pylos and harbours and the jungle-edge town of Tizamo strung between the trees. In both, the native death-customs persist openly enough to unsettle the colonists: the dead carried to burial in coffins, ancestor-bones kept in the home, and the white feathers of the old feathered-serpent god worn as marks of standing. To a Loen gentleman it is a land of "kind and obedient servants"; to the Balam people it is occupation.', null, 5, 'balam', '{}', '{}', ARRAY['southern-continent', 'balam', 'east-balam', 'west-balam', 'colony', 'fifth-epoch'], 245),
  ('southern-continent-tribes', 'The Tribes of the Southern Continent', 'location', 'The native peoples of the Southern Continent are tribes scattered through jungle and desert, organized around shamanistic leaders — spirit-warlocks who speak with the dead and the spirits — and bound by a faith far older than the colonists who now rule them. Their oldest god was Death itself, so their whole way of life is steeped in the grave: they keep the bones of their ancestors close, bear their dead to rest in coffins, and treat dying not as an ending but as a passage. Some tribes are nocturnal, moving and worshipping by night; their feather-marked relics and altars are dangerous things, prized and feared by the Northern armies that have plundered them. Under colonization the tribes have been conquered, enslaved, and worked on the plantations and in the mines, sold as servants and sacrificed to the colonists'' greed — and so, beneath the obedient surface the colonists prize, runs a current of hatred and revolt that the death-faith and the resurgent empire-cult alike know how to stir.', null, 5, 'balam', '{}', '{}', ARRAY['southern-continent', 'balam', 'tribes', 'shamanism', 'native-belief', 'fifth-epoch'], 235),
  ('balam-star-highlands', 'The Star Highlands & the Client Kingdoms', 'location', 'Beyond the two Balams the Southern Continent runs on into a patchwork of conquered and client lands. The Star Highlands hold the Highlands Kingdom, a native realm raised after the empire''s fall and now kept on a short leash as a satellite state under heavy Loen and Intis control — its founder-king''s daughter, Reinette Tinekerr, a name spoken with weight in its halls, and the Rose School of Thought quietly woven through its affairs. South and inland lie the Haagenti Plains, and the Paz Valley, where the Paz Kingdom rose in the power-vacuum the dead god left behind only to be destroyed by Loen and Intis together. Where faith in the old death-god has faded, the dead do not always rest: there have been seasons when the undead plagued these regions and emptied them. It is a continent of borders drawn by foreign hands, of native crowns reduced to puppets, and of old powers still stirring in the back-country the colonists have never truly tamed.', null, 5, 'balam', '{}', '{}', ARRAY['southern-continent', 'balam', 'star-highlands', 'highlands-kingdom', 'geography', 'fifth-epoch'], 230),
  ('berserk-sea', 'The Berserk Sea', 'location', 'The Berserk Sea is the storm-wracked water that walls the Southern Continent off from the North — the topmost of the Five Seas, and the one barrier every traveller to the colonies must cross. It was not always there: it was torn open by catastrophe at the end of the Fourth Epoch, when the death-god the South had worshipped was slain and his dying ruined the ocean. Now it churns with ceaseless thunder and lightning, a chaotic magnetism that sends compass-needles spinning and renders even wireless telegraphs all but useless, and storms that rise without warning. Only a handful of sea-routes are reckoned passable at all, and every voyage across is long, costly, and dangerous; ships are lost to it every season. It is why the Balam colonies feel so remote from the mainland that rules them — weeks of perilous water lie between — and why the sailors who run the crossing are a breed apart. Among them an old story persists: that the dead god''s tomb lies somewhere beneath the raging deep.', null, 5, 'balam', '{}', '{}', ARRAY['southern-continent', 'balam', 'berserk-sea', 'geography', 'barrier', 'fifth-epoch'], 240),
  ('balam-empire-ruins', 'The Ruins of the Balam Empire', 'location', 'Scattered the length of the Southern Continent stand the ruins of the empire that once ruled it all: the broken step-pyramids, drowned temples, and great mausolea of the Balam Empire of the death-god, swallowed now by jungle or half-buried in the plains. Their stones are carved everywhere with the feathered serpent that was the dead god''s sign, and their tombs were built to honour death above all things — so they are rich with grave-goods and old sealed relics, and they draw the greedy and the devout in equal measure: colonial expeditions, orthodox-church investigators, relic-hunting adventurers, and the death-cult that holds the sites holy. Near Tizamo in West Balam a tomb a thousand years old is famed for an ancient death-mask sought by stranger hands than archaeologists''. The colonial powers cart off what they can pry loose; the natives guard what they can; and in the deep jungle some of the old empire''s tombs have never been opened at all, waiting in the green dark for whoever is fool enough to find them.', null, 5, 'balam', '{}', '{}', ARRAY['southern-continent', 'balam', 'balam-empire', 'ruins', 'fifth-epoch'], 240),
  ('death-undersea-mausoleum', 'The Death-God''s Tomb Beneath the Berserk Sea', 'location', 'Beneath the raging Berserk Sea, the sailors'' story runs, lies the tomb of Death himself — and the story is true. When the orthodox gods united and slew the Underworld Emperor at the close of the Fourth Epoch, the same catastrophe that drowned the sea hid his corpse and his legacy somewhere in its depths, sealed away from any but one who carries the right key. To raise it would be to lay hands on the inheritance of a Sequence-0 god of death — and, the death-cult believes, the means to bring the first Underworld Emperor back into the world. The Numinous Episcopate covets it above all things, for it is the keystone of their long work of resurrection; and the undying son of the dead god is said to know the sunless ways down to it. The Church of the Evernight Goddess, who took the authority over death for her own when the old god fell, would drown the whole continent before she let that tomb be opened.', null, 5, 'balam', '{}', ARRAY[4], ARRAY['southern-continent', 'balam', 'berserk-sea', 'death-pathway', 'secret', 'fifth-epoch'], 220),
  ('church-of-death', 'The Church of Death (Balam Empire)', 'organization', 'The Church of Death was the state religion of the Balam Empire that ruled the Southern Continent through the Fourth Epoch — the faith of the Underworld Emperor, the god the histories simply call Death, first sovereign of the dead. Its priesthood deified death and the grave: it taught that dying is no ending but a threshold that may be crossed and even reversed, kept the full mysteries of the death-god''s path, and governed the southern plains and rainforests hand in hand with the imperial Eggers line descended from the god himself. Its symbol was the feathered serpent, and its rites — coffins, ancestor-bones, blood offerings — set the death-soaked customs the Balam tribes keep to this day. When the orthodox gods united and slew Death near the epoch''s end, the empire collapsed and the Church fell with it, its archbishops and faithful scattered or hunted down. From those remnants, and from the surviving Eggers, would grow the secret Numinous Episcopate of the Fifth Epoch — so the dead empire''s church never wholly died.', null, 4, null, '{}', '{}', ARRAY['church-of-death', 'balam-empire', 'death-pathway', 'fourth-epoch', 'history', 'religion'], 235),
  ('southern-death-worship', 'The Death-Worship of the Balam Tribes', 'organization', 'Long after the empire fell, the death-worship of the Southern Continent endures among its colonized tribes — the folk faith the orthodox churches have outlawed. In the old imperial fiefs the people still keep the dead god''s ways: they bury their dead apart and keep ancestor-bones in the home, bear the dead to rest in coffins, and wear the white feathers of the feathered serpent that was his sign. It is not a church but a creed of village shamans and grave-rites, woven through every part of native life — and in the deep jungles of West Balam its old sacrifices still run red. To the Northern colonists and the Church of the Evernight Goddess, who now holds the authority over death the old god once wielded, it is heresy and savagery to be stamped out, and its shrines are pulled down and its priests hunted. To the Balam people it is simply who they are, and the longer the colonists try to burn it out of them, the more it becomes a banner for revolt.', null, 5, 'balam', '{}', '{}', ARRAY['southern-continent', 'balam', 'death-worship', 'native-belief', 'shamanism', 'religion', 'fifth-epoch'], 235),
  ('numinous-episcopate-southern-roots', 'Numinous Episcopate — Roots in the Fallen Empire', 'organization', 'The Numinous Episcopate''s roots run back to the fall of the Balam Empire. When the death-god perished and the Church of Death collapsed, a few surviving members of the Eggers family — the imperial line descended from the god himself — bound themselves into a secret society to undo that death: to resurrect the first Underworld Emperor and, with him, raise the empire again and cast the Northern colonists into the sea. "Only death endures forever," they say. From the Southern Continent the brotherhood spread; nearly eradicated by the Seven Orthodox Churches in the colonial era, it survived stubbornly and crept into the nations of the Northern Continent. Its strongest arm is the Royal Family Faction of the Eggers descendants, led by Sia Palenque Eggers; another, the Artificial Death Faction, is led by Haiter, once an archbishop of the old Church of Death. To the Church of the Evernight Goddess — who took the dead god''s authority over death for her own — the Episcopate is among the deadliest heresies alive, a wound from the elder ages that has never closed.', null, 5, null, ARRAY['Sia Palenque Eggers', 'Haiter'], ARRAY[4], ARRAY['numinous-episcopate', 'balam-empire', 'eggers-family', 'death-pathway', 'secret-organization', 'southern-continent', 'spoiler'], 240),
  ('npc-sia-palenque-eggers', 'Sia Palenque Eggers — Heir of the Death-Empire', 'npc', 'Sia Palenque Eggers leads the Royal Family Faction, the strongest arm of the Numinous Episcopate — and she is of the blood of Death itself, a descendant of the Underworld Emperor Salinger through the imperial Eggers line of the fallen Balam Empire. To her the colonization of the Southern Continent is a wound that can be healed only one way: by resurrecting the first Underworld Emperor, raising the death-empire from its ruins, and casting the Northern churches into the sea. She commands saint-tier apostles and the full inheritance of the death-god''s faith, and she hunts the bodies, Beyonder characteristics, and sealed relics that a true resurrection would demand — above all the dead god''s legacy hidden beneath the Berserk Sea. She is kin, distant and estranged, to the undying Azik Eggers, who walks a far gentler road than hers. To the Church of the Evernight Goddess she is among the most dangerous heretics alive; to her own people, the rightful heir of a stolen throne.', null, 5, 'balam', ARRAY['Sia Palenque Eggers', 'Salinger', 'Azik Eggers'], ARRAY[4], ARRAY['numinous-episcopate', 'eggers-family', 'death-pathway', 'balam', 'southern-continent', 'spoiler'], 230),
  ('npc-haiter', 'Haiter — The Last Archbishop of Death', 'npc', 'Haiter leads the Artificial Death Faction of the Numinous Episcopate from the jungles of West Balam — and he is old beyond ordinary reckoning, for he was once an archbishop of the Church of Death in the days of the Balam Empire itself, a survivor of the empire''s fall who has carried the dead god''s faith down more than a thousand years. Where the Royal Family Faction trusts the Eggers bloodline to provide the vessel for the god''s return, Haiter''s faction pursues another road: to manufacture that vessel by craft and ritual rather than wait on a living heir. Patient, learned, and utterly devoted, he keeps saints and an angel of the faith about him in the deep colony, treats the orthodox churches'' centuries of persecution as a delay rather than a defeat, and reckons time in epochs. He has outlived empires and emperors both; he intends to outlive the colonists too, and see Death walk the world again.', null, 5, 'balam', ARRAY['Haiter', 'Sia Palenque Eggers'], ARRAY[4], ARRAY['numinous-episcopate', 'church-of-death', 'death-pathway', 'balam', 'southern-continent', 'spoiler'], 210);
